import pytest
import requests

BASE_URL = "https://banking-api.example.com"
REQUEST_COUNT = 10

@pytest.fixture
def fresh_user_token():
    return <fixture: fresh_user_token>

def test_requests_within_quota_succeed(fresh_user_token):
    headers = {"Authorization": f"Bearer {fresh_user_token}"}
    statuses = []
    for _ in range(REQUEST_COUNT):
        r = requests.get(f"{BASE_URL}/accounts", headers=headers, timeout=10)
        statuses.append(r.status_code)
    assert all(s < 400 for s in statuses), (
        f"Expected all 2xx but got: {statuses}"
    )
    assert 429 not in statuses, "Rate limit triggered within quota"

import pytest
import requests

BASE_URL = "https://banking-api.example.com"
QUOTA = 60

@pytest.fixture
def fresh_user_token():
    return <fixture: fresh_user_token>

def test_sixty_first_request_returns_429_with_retry_after(fresh_user_token):
    headers = {"Authorization": f"Bearer {fresh_user_token}"}
    for _ in range(QUOTA):
        requests.get(f"{BASE_URL}/accounts", headers=headers, timeout=10)
    overage = requests.get(f"{BASE_URL}/accounts", headers=headers, timeout=10)
    assert overage.status_code == 429, (
        f"Expected 429, got {overage.status_code}"
    )
    retry_after = overage.headers.get("Retry-After")
    assert retry_after is not None, "Retry-After header missing on 429"
    assert int(retry_after) > 0, (
        f"Retry-After must be a positive integer, got: {retry_after}"
    )

import pytest
import requests

BASE_URL = "https://banking-api.example.com"
QUOTA = 60

@pytest.fixture
def fresh_user_token():
    return <fixture: fresh_user_token>

def test_boundary_60th_allowed_and_61st_rejected(fresh_user_token):
    headers = {"Authorization": f"Bearer {fresh_user_token}"}
    for _ in range(QUOTA - 1):
        requests.get(f"{BASE_URL}/accounts", headers=headers, timeout=10)
    boundary_resp = requests.get(
        f"{BASE_URL}/accounts", headers=headers, timeout=10
    )
    assert boundary_resp.status_code != 429, (
        f"60th request (boundary) must not be throttled, got {boundary_resp.status_code}"
    )
    over_resp = requests.get(
        f"{BASE_URL}/accounts", headers=headers, timeout=10
    )
    assert over_resp.status_code == 429, (
        f"61st request must return 429, got {over_resp.status_code}"
    )
    retry_after = over_resp.headers.get("Retry-After")
    assert retry_after is not None, "Retry-After header missing"
    assert 0 < int(retry_after) <= 60, (
        f"Retry-After out of expected range: {retry_after}"
    )
